}
return [{ json: { ...prev, lead_found: false, match_method: 'none' } }];

const items = $input.all().map(i => i.json);
const candidate = items.find(c => c && c.contacts && c.contacts.companies && c.contacts.companies.leads && c.contacts.companies.leads.length > 0);
const prev = $('Extract Sender Domain').first().json;
if (candidate) {
  const lead = candidate.contacts.companies.leads[0];
  return [{ json: {
    lead_found: true,
    lead_id: lead.id,
    lead_status: lead.status,
    match_method: 'email_contact',
    from_email: prev.from_email,
    sender_domain: prev.sender_domain,
    subject: prev.subject,
    body_preview: prev.body_preview,
    received_at: prev.received_at,
    salesman_id: prev.salesman_id
  }}];
}
return [{ json: { ...prev, lead_found: false, match_method: 'none' } }];

const items = $input.all().map(i => i.json);
const lead = items.find(l => l && l.id) || null;
const prev = $('Extract Sender Domain').first().json;
if (lead) {
  return [{ json: {
    lead_found: true,
    lead_id: lead.id,
    lead_status: lead.status,
    match_method: 'domain',
    from_email: prev.from_email,
    sender_domain: prev.sender_domain,
    subject: prev.subject,
    body_preview: prev.body_preview,
    received_at: prev.received_at,
    salesman_id: prev.salesman_id
  }}];
}
return [{ json: { ...prev, lead_found: false, match_method: 'none' } }];

const candidates = $input.all().map(i => i.json).filter(l => l && l.id);
const prev = $('Extract Sender Domain').first().json;
const senderDomain = prev.sender_domain;

if (candidates.length === 0) {
  return [{ json: { ...prev, lead_found: false, match_method: 'none' } }];
}

function rootDomain(d) {
  return (d || '').replace(/\.[a-z]{2,}$/i, '').replace(/^(www\.)?/, '').toLowerCase();
}

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = Math.min(
        dp[i-1][j] + 1,
        dp[i][j-1] + 1,
        dp[i-1][j-1] + (a[i-1] !== b[j-1] ? 1 : 0)
      );
    }
  }
  return dp[m][n];
}

const senderRoot = rootDomain(senderDomain);
let bestMatch = null;
let bestScore = 0;

for (const lead of candidates) {
  const leadDomain = (lead.domain || '').toLowerCase();
  const leadRoot = rootDomain(leadDomain);
  let score = 0;
  if (senderDomain.includes(leadDomain) || leadDomain.includes(senderDomain)) score += 3;
  if (senderRoot.includes(leadRoot) || leadRoot.includes(senderRoot)) score += 2;
  if (senderRoot === leadRoot && senderRoot.length >= 3) score += 5;
  const dist = levenshtein(senderDomain, leadDomain);
  if (dist <= 2) score += (3 - dist);
  if (score > bestScore) {
    bestScore = score;
    bestMatch = lead;
  }
}

if (bestMatch && bestScore >= 2) {
  return [{ json: {
    lead_found: true,
    lead_id: bestMatch.id,
    lead_status: bestMatch.status,
    match_method: 'fuzzy',
    from_email: prev.from_email,
    sender_domain: prev.sender_domain,
    subject: prev.subject,
    body_preview: prev.body_preview,
    received_at: prev.received_at,
    salesman_id: prev.salesman_id
  }}];
}

return [{ json: { ...prev, lead_found: false, match_method: 'none' } }];

const items = $input.all().map(i => i.json);
const waveLead = items.find(wl => wl && wl.id) || null;
const prev = $('Merge Match Results').first().json;
return [{ json: {
  ...prev,
  wave_lead_id: waveLead ? waveLead.id : null,
  wave_id: waveLead ? waveLead.wave_id : null,
  has_wave_lead: !!waveLead
}}];

